INSERT INTO public.servicios (id, name_es, name_en, description_es, description_en, "order") VALUES
  ('ecommerce', 'Quiero vender mis productos por internet', 'I want to sell my products online', 'Tienda online completa: catálogo, carrito, pagos y panel para que manejes tus productos tú mismo.', 'Full online store: catalog, cart, payments and a panel so you manage your own products.', 1),
  ('seo-web', 'Quiero que mi negocio aparezca en Google y lo encuentren', 'I want my business to show up on Google', 'Página profesional optimizada para que tus clientes te encuentren cuando busquen lo que ofreces.', 'Professional page optimized so your customers find you when they search for what you offer.', 2),
  ('portfolio', 'Quiero mostrar mi trabajo o mi carrera', 'I want to showcase my work or career', 'Portafolio o CV digital que transmite quién eres y qué has logrado, de forma profesional.', 'Portfolio or digital resume that shows who you are and what you have achieved, professionally.', 3),
  ('landing', 'Quiero promocionar algo puntual', 'I want to promote something specific', 'Landing page enfocada en convertir visitantes en clientes para un producto, servicio o evento.', 'Landing page focused on converting visitors into customers for a product, service, or event.', 4),
  ('custom', 'No estoy seguro / quiero que me asesores', 'I''m not sure / I''d like some advice', 'Cuéntame tu idea y te oriento hacia la solución más adecuada para tu negocio.', 'Tell me your idea and I''ll guide you toward the best solution for your business.', 5)
INSERT INTO public.proyectos (slug, category, service_id, featured, business_es, business_en, description_es, description_en, objective_es, objective_en, problem_es, problem_en, solution_es, solution_en, challenges_es, challenges_en, results_es, results_en, technologies, live_url) VALUES
  ('tienda-artesanias-quito', 'demo', 'ecommerce', true, 'Artesanías del Ecuador', 'Ecuador Crafts', 'Tienda online para un taller artesanal, con catálogo, pagos y gestión de inventario propia.', 'Online store for an artisan workshop, with catalog, payments and self-managed inventory.', 'Que el taller pudiera vender fuera de Instagram y llegar a clientes que no usan redes sociales.', 'Get the workshop selling beyond Instagram and reach customers who don''t use social media.', 'Un taller artesanal en Quito vendía solo por Instagram, perdiendo clientes que no usaban redes sociales.', 'An artisan workshop in Quito was selling only through Instagram, missing customers who don''t use social media.', 'Le hice una tienda online donde los clientes pueden ver el catálogo completo, pagar con tarjeta y el dueño maneja su inventario sin depender de nadie.', 'I built them an online store where customers can browse the full catalog, pay by card, and the owner manages their inventory independently.', 'Necesitaba un checkout simple para clientes poco familiarizados con compras online, y sincronizar el inventario en tiempo real para evitar vender piezas artesanales de stock único que ya no existían.', 'The checkout had to stay simple for customers unfamiliar with online shopping, and inventory needed real-time sync to avoid selling one-of-a-kind pieces that were already gone.', 'El taller ahora vende directamente desde su web, sin depender de que un cliente le escriba por Instagram, y controla su inventario sin hojas de cálculo.', 'The workshop now sells directly from its website instead of relying on Instagram DMs, and manages inventory without spreadsheets.', ARRAY['Next.js', 'Supabase', 'Stripe', 'TypeScript'], NULL),
  ('restaurante-la-ronda', 'demo', 'seo-web', true, 'Restaurante La Ronda', 'La Ronda Restaurant', 'Sitio web optimizado para SEO local de un restaurante del centro histórico de Quito.', 'Local-SEO-optimized website for a restaurant in Quito''s historic center.', 'Que el restaurante apareciera en Google para quienes buscan dónde comer en el centro, sin depender solo del boca a boca.', 'Get the restaurant showing up on Google for people searching where to eat downtown, instead of relying only on word of mouth.', 'Un restaurante del centro histórico no aparecía en Google y sus clientes llegaban solo por recomendación boca a boca.', 'A historic center restaurant wasn''t showing up on Google and customers only found it through word of mouth.', 'Le construí una página optimizada para buscadores con menú, fotos, ubicación y reseñas.', 'I built them a search-optimized page with menu, photos, location and reviews.', 'El reto fue optimizar la velocidad de carga y la estructura SEO sin perder el diseño visual que el dueño quería, y configurar bien Google Business para que ambos canales trabajaran juntos.', 'The challenge was optimizing load speed and SEO structure without losing the visual design the owner wanted, and configuring Google Business correctly so both channels worked together.', 'En tres meses empezó a aparecer en los primeros resultados locales de Google.', 'Within three months it started appearing in top local Google results.', ARRAY['Next.js', 'Tailwind CSS', 'TypeScript'], NULL),
  ('portafolio-fotografa', 'demo', 'portfolio', true, 'Daniela López — Fotógrafa', 'Daniela López — Photographer', 'Portafolio visual para una fotógrafa profesional, con galerías por categoría y carga rápida de imágenes.', 'Visual portfolio for a professional photographer, with category galleries and fast image loading.', 'Que pudiera mostrar su trabajo de forma profesional a clientes corporativos, más allá de Instagram.', 'Let her present her work professionally to corporate clients, beyond Instagram.', 'Una fotógrafa profesional compartía su trabajo solo en Instagram, sin poder presentar un portafolio profesional a clientes corporativos.', 'A professional photographer was sharing work only on Instagram, unable to present a professional portfolio to corporate clients.', 'Le diseñé un portafolio visual con galerías por categoría, página de contacto y carga ultra-rápida de imágenes para que nunca pierda a un cliente por lentitud.', 'I designed a visual portfolio with galleries by category, a contact page and ultra-fast image loading so she never loses a client due to slow load times.', 'El reto fue optimizar decenas de imágenes en alta resolución sin sacrificar calidad visual, manteniendo tiempos de carga rápidos incluso en conexiones móviles.', 'The challenge was optimizing dozens of high-resolution images without sacrificing visual quality, keeping load times fast even on mobile connections.', 'Ahora envía un solo link a marcas y agencias en vez de compartir carpetas de Drive o su perfil de Instagram.', 'She now sends a single link to brands and agencies instead of sharing Drive folders or her Instagram profile.', ARRAY['Next.js', 'Framer Motion', 'Supabase Storage'], NULL),
  ('landing-curso-online', 'demo', 'landing', false, 'Curso de Finanzas Personales', 'Personal Finance Course', 'Landing page de lanzamiento para un curso online de finanzas personales.', 'Launch landing page for an online personal finance course.', 'Convertir a personas interesadas en el curso en compradores, con una página enfocada 100% en la venta.', 'Turn people interested in the course into buyers, with a page focused entirely on conversion.', 'Un coach financiero lanzaba un curso pero no tenía una página convincente para convertir interesados en compradores.', 'A financial coach was launching a course but had no convincing page to convert interested people into buyers.', 'Le hice una landing page con testimonios, módulos del curso, contador de plazas y botón de compra directo.', 'I built a landing page with testimonials, course modules, a seat counter and a direct purchase button.', 'El reto fue generar urgencia real (cupos limitados) sin que se sintiera forzado, y conectar el botón de compra directo con la pasarela de pago sin fricciones.', 'The challenge was creating real urgency (limited spots) without it feeling forced, and connecting the direct purchase button to the payment gateway without friction.', 'Vendió el 80% de los cupos disponibles en la primera semana de lanzamiento.', 'They sold 80% of available spots in the first week after launch.', ARRAY['Next.js', 'Tailwind CSS', 'Stripe'], NULL),
  ('app-gestion-inventarios', 'cliente', 'custom', false, 'Distribuidora El Sol', 'El Sol Distributors', 'App web a medida para reemplazar las hojas de cálculo de inventario de una distribuidora.', 'Custom web app to replace a distributor''s spreadsheet-based inventory.', 'Que la distribuidora dejara de perder el rastro de productos y de duplicar pedidos a proveedores por errores manuales.', 'Stop the distributor from losing track of products and duplicating supplier orders due to manual errors.', 'Una distribuidora local manejaba su inventario en hojas de cálculo, perdiendo el rastro de productos y generando pedidos duplicados a proveedores.', 'A local distributor was managing inventory in spreadsheets, losing track of products and generating duplicate supplier orders.', 'Les desarrollé una app web a medida con panel de control, alertas de stock bajo y generación automática de órdenes de compra.', 'I built a custom web app with a dashboard, low-stock alerts and automatic purchase order generation.', 'El mayor reto fue diseñar las alertas de stock bajo para que fueran útiles sin saturar al equipo de notificaciones, y migrar años de datos históricos desde hojas de cálculo sin perder información.', 'The biggest challenge was designing low-stock alerts that were useful without overwhelming the team with notifications, and migrating years of historical data from spreadsheets without losing information.', 'Redujeron los errores de inventario en un 90% y dejaron de generar pedidos duplicados a proveedores.', 'They reduced inventory errors by 90% and stopped generating duplicate supplier orders.', ARRAY['React', 'Node.js', 'PostgreSQL', 'Tailwind CSS'], NULL),
  ('sitio-corredora-propiedades', 'cliente', 'seo-web', false, 'Corredora de Propiedades MG', 'MG Real Estate', 'Rediseño de sitio web con SEO completo para una corredora de propiedades.', 'Full website redesign with complete SEO for a real estate agency.', 'Que el sitio volviera a aparecer en Google y generara consultas reales de compradores interesados.', 'Get the site showing up on Google again and generating real inquiries from interested buyers.', 'Una corredora de propiedades tenía un sitio web desactualizado que no aparecía en Google y no generaba leads.', 'A real estate agent had an outdated website that didn''t appear on Google and generated no leads.', 'Le rediseñé el sitio con listado de propiedades, filtros por zona/precio, formulario de contacto integrado y SEO completo.', 'I redesigned their site with property listings, filters by area/price, an integrated contact form and full SEO.', 'El reto fue reestructurar todo el SEO técnico de un sitio desactualizado (URLs, metadatos, velocidad) sin perder el poco tráfico que ya tenía durante la migración.', 'The challenge was restructuring all the technical SEO of an outdated site (URLs, metadata, speed) without losing the little traffic it already had during the migration.', 'En 2 meses triplicó las consultas de clientes interesados en propiedades.', 'Within 2 months, inquiries from interested buyers tripled.', ARRAY['Next.js', 'Tailwind CSS', 'TypeScript', 'Supabase'], 'https://mg-propiedades.example.com'),
  ('landing-evento-tech', 'demo', 'landing', false, 'Conferencia TechQuito 2025', 'TechQuito 2025 Conference', 'Landing page de registro para una conferencia de tecnología en Quito.', 'Registration landing page for a tech conference in Quito.', 'Registrar asistentes y patrocinadores en menos de dos semanas, con un proceso de pago integrado.', 'Register attendees and sponsors in under two weeks, with an integrated payment process.', 'La organización de una conferencia tech necesitaba una landing para registrar asistentes y patrocinadores en menos de dos semanas.', 'A tech conference organization needed a landing page to register attendees and sponsors in under two weeks.', 'Construí una landing con contador regresivo, formulario de registro, grid de speakers y pasarela de pago.', 'I built a landing page with a countdown timer, registration form, speaker grid and payment gateway.', 'El reto fue construir y lanzar la página completa —incluyendo pagos— en menos de dos semanas, sin sacrificar el diseño ni la confiabilidad del checkout.', 'The challenge was building and launching the entire page —including payments— in under two weeks, without sacrificing design or checkout reliability.', 'Registraron más de 300 asistentes en los primeros 10 días desde el lanzamiento.', 'They registered over 300 attendees in the first 10 days after launch.', ARRAY['Next.js', 'Stripe', 'Tailwind CSS', 'TypeScript'], NULL)
